// 图标映射表，通过平台code获取对应图标组件
export const PlatformIconMap: Record<string, React.FC<IconProps>> = {
  xiaohongshu: XiaohongshuIcon,
  douyin: DouyinIcon,
  weibo: WeiboIcon,
  bilibili: BilibiliIcon,
  zhihu: ZhihuIcon,
  wechat: WechatIcon,
}

/**
 * 通用平台图标组件
 * 根据平台code自动渲染对应图标
 */
interface PlatformIconProps extends IconProps {
  platformCode: string
  fallback?: React.ReactNode
}

export const PlatformIcon: React.FC<PlatformIconProps> = ({
  platformCode,
  className = '',
  size = 24,
  fallback = '📱',
}) => {
  const IconComponent = PlatformIconMap[platformCode]

  if (IconComponent) {
    return <IconComponent className={className} size={size} />
  }

  // 如果没有对应图标，显示fallback
  return <span className={className} style={{ fontSize: size * 0.8 }}>{fallback}</span>
}

export default PlatformIcon
